1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE = 0.1;
3	
4	interface QuoteStep {
5	  op: "quote";
6	  items: { type: string }[];
7	}
8	
9	interface Scenario {
10	  customer: { yearsWithMHPCO: number };
11	  steps: QuoteStep[];
12	}
13	
14	interface QuoteResult {
15	  premium: number;
16	}
17	
18	const BASE_PREMIUMS: Record<string, number> = {
19	  sword: 100,
20	  amulet: 60,
21	  staff: 80,
22	  potion: 40,
23	  rune: 25,
24	  moonstone: 25,
25	};
26	
27	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
28	const BLOCK_SIZE = 3;
29	const BLOCK_PREMIUM = 60;
30	
31	const formsBlock = (type: string, count: number): boolean =>
32	  COMPONENT_TYPES.has(type) && count === BLOCK_SIZE;
33	
34	const typeBasePremium = (type: string, count: number): number => {
35	  if (formsBlock(type, count)) return BLOCK_PREMIUM;
36	  return count * BASE_PREMIUMS[type];
37	};
38	
39	const policyBasePremium = (items: { type: string }[]): number => {
40	  const counts = new Map<string, number>();
41	  for (const item of items) {
42	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
43	  }
44	  return [...counts].reduce(
45	    (base, [type, count]) => base + typeBasePremium(type, count),
46	    0,
47	  );
48	};
49	
50	// Premiums round up (in the MHPCO's favor); toFixed guards against
51	// floating-point error nudging an exact value over an integer boundary.
52	const roundUpPremium = (amount: number): number =>
53	  Math.ceil(Number(amount.toFixed(6)));
54	
55	const quotePremium = (step: QuoteStep): number => {
56	  const base = policyBasePremium(step.items);
57	  const total = base * (1 + FIRST_INSURANCE_SURCHARGE) + PROCESSING_FEE;
58	  return roundUpPremium(total);
59	};
60	
61	export const runScenario = (scenario: Scenario): { results: QuoteResult[] } => {
62	  return { results: scenario.steps.map((step) => ({ premium: quotePremium(step) })) };
63	};
