29	    const result = runScenario({
30	      customer: { yearsWithMHPCO: 0 },
31	      steps: [
32	        {
33	          op: "quote",
34	          items: [{ type: "amulet", material: "silver", enchantment: 2, cursed: false }],
35	        },
36	      ],
37	    });
38	    expect(result.results[0]).toEqual({ premium: 71 });
39	  });
