47	        },
48	      ],
49	    });
50	    expect(result.results[0]).toEqual({ premium: 93 });
51	  });
52	  it("single potion (base 40 G) → premium 49 G (40 + 4 first insurance + 5 fee)", () => {
53	    const result = runScenario({
54	      customer: { yearsWithMHPCO: 0 },
55	      steps: [
56	        {
57	          op: "quote",
58	          items: [{ type: "potion", material: "glass", enchantment: 1, cursed: false }],
59	        },
60	      ],
61	    });
62	    expect(result.results[0]).toEqual({ premium: 49 });
63	  });
64	
65	  // --- Components and building blocks ---
66	  it("2 runes (base 50 G, no block) → premium 60 G (50 + 5 first insurance + 5 fee)", () => {
67	    const result = runScenario({
68	      customer: { yearsWithMHPCO: 0 },
69	      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }] }],
70	    });
71	    expect(result.results[0]).toEqual({ premium: 60 });
72	  });
73	  it("3 runes (block, base 60 G) → premium 71 G (60 + 6 first insurance + 5 fee)", () => {
74	    const result = runScenario({
75	      customer: { yearsWithMHPCO: 0 },
76	      steps: [
77	        { op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }] },
78	      ],
79	    });
80	    expect(result.results[0]).toEqual({ premium: 71 });
81	  });
82	  it("4 runes (no block, base 100 G) → premium 115 G (100 + 10 first insurance + 5 fee)", () => {
83	    const result = runScenario({
84	      customer: { yearsWithMHPCO: 0 },
85	      steps: [
86	        {
87	          op: "quote",
88	          items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }],
89	        },
90	      ],
91	    });
92	    expect(result.results[0]).toEqual({ premium: 115 });
93	  });
94	  it("7 runes (no block, base 175 G) → premium 198 G (175 × 1.1 + 5 = 197.5, rounded up)", () => {
95	    const result = runScenario({
96	      customer: { yearsWithMHPCO: 0 },
97	      steps: [
98	        {
99	          op: "quote",
100	          items: Array.from({ length: 7 }, () => ({ type: "rune" })),
101	        },
102	      ],
103	    });
104	    expect(result.results[0]).toEqual({ premium: 198 });
105	  });
106	
107	  // --- "Alike" components ---
108	  it("2 runes + 1 moonstone (no block, base 75 G) → premium 88 G (75 × 1.1 + 5 = 87.5, up)", () => {
109	    const result = runScenario({
110	      customer: { yearsWithMHPCO: 0 },
111	      steps: [
112	        {
113	          op: "quote",
114	          items: [{ type: "rune" }, { type: "rune" }, { type: "moonstone" }],
115	        },
116	      ],
117	    });
118	    expect(result.results[0]).toEqual({ premium: 88 });
