121	    const result = runScenario({
122	      customer: { yearsWithMHPCO: 0 },
123	      steps: [
124	        {
125	          op: "quote",
126	          items: [
127	            { type: "rune" },
128	            { type: "rune" },
129	            { type: "rune" },
130	            { type: "moonstone" },
131	            { type: "moonstone" },
132	            { type: "moonstone" },
133	          ],
134	        },
135	      ],
136	    });
137	    expect(result.results[0]).toEqual({ premium: 137 });
138	  });
139	
140	  // --- Premium modifiers in isolation ---
141	  it.todo("cursed item adds 50 % risk surcharge of its base premium");
142	  it.todo("highly enchanted item (enchantment ≥ 5) adds 30 % risk surcharge");
143	  it.todo("long-standing customer (≥ 2 years) receives 20 % loyalty discount");
144	  it.todo("first insurance carries 10 % initial assessment surcharge");
145	  it.todo("each contract after the first receives 15 % follow-up discount");
146	  it.todo("5 G processing fee is added to every premium");
147	
148	  // --- Modifier scope on multi-item policies ---
149	  it.todo("cursed sword + plain amulet → 210 G before fee (surcharge on cursed item's base only)");
150	  it.todo("item modifiers apply per item; policy modifiers apply to policy base; fee added last");
151	
152	  // --- Modifier thresholds ---
153	  it.todo("customer with exactly 2 years → loyalty discount applies");
154	  it.todo("sword with exactly enchantment 5 → high-enchantment surcharge applies");
155	  it.todo("sword with exactly enchantment 5 and cursed → both surcharges apply");
156	  it.todo("sword with enchantment 4 → no high-enchantment surcharge");
157	
158	  // --- Rounding in the MHPCO's favor ---
159	  it.todo("premium 197.5 G → final premium 198 G (rounded up)");
160	  it.todo("payout 350.5 G → final payout 350 G (rounded down)");
161	
162	  // --- Claim processing: standard reimbursement ---
163	  it.todo("regular sword, damage 500 G → payout 400 G (full minus 100 G deductible)");
164	  it.todo("rune damage 200 G → payout 100 G (no special clause; minus deductible)");
165	
166	  // --- Enchantment threshold vs dragon material ---
167	  it.todo("dragon sword, enchantment 8, damage 1000 G → payout 400 G (50 % then deductible)");
168	  it.todo("dragon sword, enchantment 9, damage 1000 G → payout 400 G (both clauses; 50 % wins)");
169	  it.todo("dragon sword, enchantment 5, damage 800 G → payout 700 G (full then deductible)");
170	  it.todo("steel sword, enchantment 9, damage 1000 G → payout 400 G (50 % then deductible)");
171	
172	  // --- Deductible per damage event ---
173	  it.todo("dragon attack damages sword 500 G and amulet 300 G → payout 600 G (deductible per item)");
174	
175	  // --- Multiple items of the same type ---
176	  it.todo("policy covers two swords → insurance sum 2000 G, cap 4000 G");
177	  it.todo("two sword damages on two-sword policy → each treated as separate damage with own deductible");
178	  it.todo("more damages of a type than insured (two sword damages, one sword) → claim rejected (nonzero exit)");
179	
180	  // --- Cap exhaustion ---
181	  it.todo("sword + amulet → insurance sum 1600 G, cap 3200 G");
182	  it.todo("cursed sword → cap 2000 G (based on unmodified insurance value)");
183	  it.todo("sword + 3 runes (block) → insurance sum 1750 G (block affects premium only)");
184	  it.todo("two successive 1500 G claims on 1000 G sword → payouts 1400 G then 600 G, cap remaining 600 then 0");
185	
186	  // --- Edge cases: errors ---
187	  it.todo("quote with unknown item type (broomstick) → nonzero exit, error on stderr, no results on stdout");
188	  it.todo("claim references item not in policy (amulet when only sword insured) → nonzero exit, error on stderr");
189	  it.todo("claim with negative damage amount (-200) → nonzero exit, error on stderr");
190	
191	  // --- Integration examples ---
192	  it.todo("newcomer with cursed sword (enchantment 3) → premium 165 G");
193	  it.todo("long-standing customer's second contract, cursed sword enchantment 7 → premium 160 G");
194	
195	  // --- CLI / scenario plumbing ---
196	  it.todo("results array has same length and order as input steps");
197	});
